// MDLParserInit initializes any static state used to implement MDLParser. By default the
// static state used to implement the parser is lazily initialized during the first call to
// NewMDLParser(). You can call this function if you wish to initialize the static state ahead
// of time.
func MDLParserInit() {
	staticData := &MDLParserParserStaticData
	staticData.once.Do(mdlparserParserInit)
}

// NewMDLParser produces a new parser instance for the optional input antlr.TokenStream.
func NewMDLParser(input antlr.TokenStream) *MDLParser {
	MDLParserInit()
	this := new(MDLParser)
	this.BaseParser = antlr.NewBaseParser(input)
	staticData := &MDLParserParserStaticData
	this.Interpreter = antlr.NewParserATNSimulator(this, staticData.atn, staticData.decisionToDFA, staticData.PredictionContextCache)
	this.RuleNames = staticData.RuleNames
	this.LiteralNames = staticData.LiteralNames
	this.SymbolicNames = staticData.SymbolicNames
	this.GrammarFileName = "MDLParser.g4"

	return this
}

